import type { ComponentProps, ComponentRef } from 'react';
import { Popover as PopoverPrimitive, usePopover, usePopoverContext } from '@ark-ui/react/popover';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Popover.module.css';

function PopoverRoot(props: ComponentProps<typeof PopoverPrimitive.Root>) {
  return <PopoverPrimitive.Root {...props} />;
}

function PopoverRootProvider(props: ComponentProps<typeof PopoverPrimitive.RootProvider>) {
  return <PopoverPrimitive.RootProvider {...props} />;
}

const PopoverAnchor = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Anchor>,
  ComponentProps<typeof PopoverPrimitive.Anchor>
>(function PopoverAnchor({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.Anchor
      ref={ref}
      data-slot="popover-anchor"
      className={normalizeClassName(className)}
      {...props}
    />
  );
});

const PopoverTrigger = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Trigger>,
  ComponentProps<typeof PopoverPrimitive.Trigger>
>(function PopoverTrigger({ asChild, className, ...props }, ref) {
  return (
    <PopoverPrimitive.Trigger
      ref={ref}
      data-slot="popover-trigger"
      asChild={asChild}
      className={clsx(!asChild && styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverIndicator = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Indicator>,
  ComponentProps<typeof PopoverPrimitive.Indicator>
>(function PopoverIndicator({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.Indicator
      ref={ref}
      data-slot="popover-indicator"
      className={normalizeClassName(className)}
      {...props}
    />
  );
});

const PopoverPositioner = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Positioner>,
  ComponentProps<typeof PopoverPrimitive.Positioner>
>(function PopoverPositioner({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.Positioner
      ref={ref}
      data-slot="popover-positioner"
      className={clsx(styles.positioner, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverContent = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Content>,
  ComponentProps<typeof PopoverPrimitive.Content>
>(function PopoverContent({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.Content
      ref={ref}
      data-slot="popover-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverArrow = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Arrow>,
  ComponentProps<typeof PopoverPrimitive.Arrow>
>(function PopoverArrow({ className, children, ...props }, ref) {
  return (
    <PopoverPrimitive.Arrow
      ref={ref}
      data-slot="popover-arrow"
      className={clsx(styles.arrow, normalizeClassName(className))}
      {...props}
    >
      {children ?? <PopoverArrowTip />}
    </PopoverPrimitive.Arrow>
  );
});

const PopoverArrowTip = forwardRef<
  ComponentRef<typeof PopoverPrimitive.ArrowTip>,
  ComponentProps<typeof PopoverPrimitive.ArrowTip>
>(function PopoverArrowTip({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.ArrowTip
      ref={ref}
      data-slot="popover-arrow-tip"
      className={clsx(styles.arrowTip, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverTitle = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Title>,
  ComponentProps<typeof PopoverPrimitive.Title>
>(function PopoverTitle({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.Title
      ref={ref}
      data-slot="popover-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverDescription = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Description>,
  ComponentProps<typeof PopoverPrimitive.Description>
>(function PopoverDescription({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.Description
      ref={ref}
      data-slot="popover-description"
      className={clsx(styles.description, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverCloseTrigger = forwardRef<
  ComponentRef<typeof PopoverPrimitive.CloseTrigger>,
  ComponentProps<typeof PopoverPrimitive.CloseTrigger>
>(function PopoverCloseTrigger({ asChild, className, ...props }, ref) {
  return (
    <PopoverPrimitive.CloseTrigger
      ref={ref}
      data-slot="popover-close-trigger"
      asChild={asChild}
      className={clsx(!asChild && styles.closeTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

function PopoverHeader({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="popover-header" className={clsx(styles.header, className)} {...props} />;
}

function PopoverBody({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="popover-body" className={clsx(styles.body, className)} {...props} />;
}

function PopoverFooter({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="popover-footer" className={clsx(styles.footer, className)} {...props} />;
}

const PopoverContext = PopoverPrimitive.Context;

const Popover = Object.assign(PopoverRoot, {
  Root: PopoverRoot,
  RootProvider: PopoverRootProvider,
  Anchor: PopoverAnchor,
  Trigger: PopoverTrigger,
  Indicator: PopoverIndicator,
  Positioner: PopoverPositioner,
  Content: PopoverContent,
  Arrow: PopoverArrow,
  ArrowTip: PopoverArrowTip,
  Title: PopoverTitle,
  Description: PopoverDescription,
  CloseTrigger: PopoverCloseTrigger,
  Header: PopoverHeader,
  Body: PopoverBody,
  Footer: PopoverFooter,
  Context: PopoverContext,
});

export { Popover, usePopover, usePopoverContext };
export type {
  PopoverFocusOutsideEvent,
  PopoverInteractOutsideEvent,
  PopoverOpenChangeDetails,
  PopoverPointerDownOutsideEvent,
  PopoverTriggerValueChangeDetails,
  UsePopoverContext,
  UsePopoverProps,
  UsePopoverReturn,
} from '@ark-ui/react/popover';

@layer ui.components {
  .trigger,
  .closeTrigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: var(--popover-control-height, var(--size-lg));
    margin: 0;
    padding: var(--popover-control-padding-y, 0.5rem) var(--popover-control-padding-x, 0.875rem);
    border: var(--popover-control-border-width, var(--border-width-sm)) solid
      var(--popover-control-border-color, var(--color-border));
    border-radius: var(--popover-control-radius, var(--radius-md));
    background-color: var(--popover-control-bg, var(--color-background));
    color: var(--popover-control-color, var(--color-foreground));
    font: inherit;
    font-size: var(--popover-control-font-size, var(--text-md));
    line-height: var(--popover-control-line-height, var(--line-height-text-md));
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--popover-transition, var(--transition-default)),
      border-color var(--popover-transition, var(--transition-default)),
      color var(--popover-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--popover-control-bg-hover, var(--color-accent));
      }
    }

    &:active,
    &[data-state='open'] {
      background-color: var(
        --popover-control-bg-active,
        var(--popover-control-bg-hover, var(--color-accent))
      );
    }

    &:focus-visible {
      outline: var(
          --popover-focus-ring-width,
          var(--popover-control-border-width, var(--border-width-sm))
        )
        solid var(--popover-focus-ring-color, var(--color-ring));
      outline-offset: calc(
        var(
            --popover-focus-ring-width,
            var(--popover-control-border-width, var(--border-width-sm))
          ) *
          -1
      );
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--popover-disabled-opacity, var(--opacity-disabled));
    }
  }

  .positioner {
    z-index: var(--z-index, var(--z-popup));
    max-width: var(--available-width);
    outline: 0;
  }

  .content {
    position: relative;
    z-index: calc(var(--z-popup) + var(--layer-index, 0));
    box-sizing: border-box;
    width: var(--popover-width, auto);
    height: var(--popover-height, auto);
    min-width: min(var(--popover-min-width, 16rem), var(--available-width));
    max-width: min(var(--popover-max-width, 28rem), var(--available-width));
    max-height: min(var(--popover-max-height, 24rem), var(--available-height, 100dvh));
    overflow: visible;
    padding: var(--popover-padding-y, 1rem) var(--popover-padding-x, 1rem);
    border: 0;
    border-radius: var(--popover-radius, var(--radius-md));
    background-color: var(--popover-bg, var(--color-popover));
    color: var(--popover-color, var(--color-popover-foreground));
    outline: var(--popover-border-width, var(--border-width-sm)) solid
      var(--popover-border-color, var(--color-border));
    box-shadow: var(--popover-shadow, var(--shadow-lg));
    transform-origin: var(--transform-origin);

    &[data-state='open'] {
      animation: popover-enter var(--popover-transition, var(--duration-fast)) both;
    }

    &[data-state='closed'] {
      animation: popover-exit var(--popover-transition, var(--duration-fast)) both;
    }
  }

  .arrow {
    --arrow-size: var(--popover-arrow-size, 0.625rem);
    --arrow-background: var(--popover-bg, var(--color-popover));
  }

  .arrowTip {
    border-top: var(--popover-border-width, var(--border-width-sm)) solid
      var(--popover-arrow-stroke-color, var(--popover-border-color, var(--color-border)));
    border-left: var(--popover-border-width, var(--border-width-sm)) solid
      var(--popover-arrow-stroke-color, var(--popover-border-color, var(--color-border)));
  }

  .title {
    margin: 0;
    color: var(--popover-title-color, var(--popover-color, var(--color-popover-foreground)));
    font-size: var(--popover-title-font-size, var(--text-md));
    font-weight: var(--popover-title-font-weight, var(--weight-semibold));
    line-height: var(--popover-title-line-height, var(--line-height-text-md));
  }

  .description {
    margin: var(--popover-description-margin, 0);
    color: var(--popover-description-color, var(--color-muted-foreground));
    font-size: var(--popover-description-font-size, var(--text-sm));
    line-height: var(--popover-description-line-height, var(--line-height-text-sm));
  }

  .header {
    display: grid;
    gap: var(--popover-header-gap, var(--spacing-1));
  }

  .body {
    margin: var(--popover-body-margin, 0);
  }

  .footer {
    display: flex;
    align-items: center;
    justify-content: var(--popover-footer-justify, flex-end);
    gap: var(--popover-footer-gap, var(--spacing-2));
    margin: var(--popover-footer-margin, var(--spacing-3) 0 0);
  }

  @keyframes popover-enter {
    from {
      opacity: var(--popover-content-starting-opacity, 0);
      translate: var(--popover-content-starting-translate-x, 0)
        var(--popover-content-starting-translate-y, 0);
      scale: var(--popover-content-starting-scale, var(--scale-popup));
    }
  }

  @keyframes popover-exit {
    to {
      opacity: var(--popover-content-ending-opacity, 0);
      translate: var(--popover-content-ending-translate-x, 0)
        var(--popover-content-ending-translate-y, 0);
      scale: var(--popover-content-ending-scale, var(--scale-popup));
    }
  }
}

export { Popover, usePopover, usePopoverContext } from './Popover';
export type {
  PopoverFocusOutsideEvent,
  PopoverInteractOutsideEvent,
  PopoverOpenChangeDetails,
  PopoverPointerDownOutsideEvent,
  PopoverTriggerValueChangeDetails,
  UsePopoverContext,
  UsePopoverProps,
  UsePopoverReturn,
} from './Popover';
